{"code": "import json

# Query to get literature & fiction books
books_data = var_functions.query_db_17
reviews_data = var_functions.query_db_14

# Since these are file paths, we need to read them
with open(books_data, 'r') as f:
    books = json.load(f)

with open(reviews_data, 'r') as f:
    reviews = json.load(f)

# Extract numeric IDs and create mapping
book_id_map = {}
for book in books:
    book_id = book['book_id']
    # Extract numeric part from bookid_XXX
    if '_' in book_id:
        num_id = book_id.split('_')[1]
        book_id_map[num_id] = book

# Process reviews - extract numeric part from purchaseid_XXX
review_ratings = {}
for review in reviews:
    purchase_id = review['purchase_id']
    if '_' in purchase_id:
        num_id = purchase_id.split('_')[1]
        if num_id not in review_ratings:
            review_ratings[num_id] = []
        review_ratings[num_id].append(float(review['rating']))

# Find books with average rating of 5.0
perfect_books = []
for num_id, ratings in review_ratings.items():
    if num_id in book_id_map:
        avg_rating = sum(ratings) / len(ratings)
        if avg_rating == 5.0 and len(ratings) > 0:
            book = book_id_map[num_id]
            perfect_books.append({
                'title': book['title'],
                'book_id': book['book_id'],
                'categories': book['categories'],
                'avg_rating': avg_rating,
                'num_ratings': len(ratings)
            })

# Filter for Literature & Fiction category and check English language
result_books = []
for book in perfect_books:
    # Check if it's Literature & Fiction category
    if 'Literature & Fiction' in book['categories']:
        # Find the original book details to check English
        original_book = book_id_map[book['book_id'].split('_')[1]]
        if 'English' in original_book['details']:
            result_books.append(book)

print('__RESULT__:')
print(json.dumps(result_books, indent=2))"}

